-- Standalone real estate property management schema
CREATE TABLE IF NOT EXISTS real_estate_property_management_portfolio (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, name TEXT, manager TEXT, owner_name TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_property (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, portfolio_id TEXT, code TEXT, name TEXT, asset_class TEXT, jurisdiction TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_building (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, code TEXT, name TEXT, building_type TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_unit (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, building_id TEXT, code TEXT, unit_number TEXT, occupancy_status TEXT, market_rent NUMERIC(12,2), bedrooms INTEGER, bathrooms INTEGER, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_tenant (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, display_name TEXT, contact_email TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_tenant_party (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, tenant_id TEXT, lease_id TEXT, role TEXT, display_name TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_lease (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, unit_id TEXT, tenant_id TEXT, code TEXT, start_date TEXT, end_date TEXT, base_rent NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_rent_schedule (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, unit_id TEXT, code TEXT, frequency TEXT, next_due_date TEXT, amount NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_security_deposit (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, tenant_id TEXT, code TEXT, trust_account TEXT, amount NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_charge (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, tenant_id TEXT, charge_type TEXT, code TEXT, amount NUMERIC(12,2), due_date TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_cam_recovery (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, lease_id TEXT, code TEXT, recovery_basis TEXT, estimated_amount NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_maintenance_request (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, unit_id TEXT, lease_id TEXT, code TEXT, priority TEXT, summary TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_inspection (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, unit_id TEXT, lease_id TEXT, code TEXT, inspection_type TEXT, scheduled_for TEXT, result TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_vacancy (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, unit_id TEXT, code TEXT, market_ready_date TEXT, notice_date TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_renewal (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, unit_id TEXT, code TEXT, stage TEXT, offered_rent TEXT, expires_on TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_move_event (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, unit_id TEXT, code TEXT, event_type TEXT, event_date TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_delinquency_case (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, tenant_id TEXT, code TEXT, days_past_due INTEGER, balance_due NUMERIC(12,2), stage TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_notice (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, lease_id TEXT, code TEXT, notice_type TEXT, service_method TEXT, served_on TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_compliance_item (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, code TEXT, title TEXT, due_date TEXT, severity TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_vendor_work_order (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, maintenance_request_id TEXT, property_id TEXT, unit_id TEXT, code TEXT, vendor_name TEXT, scheduled_for TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_owner_statement (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, code TEXT, statement_period TEXT, net_operating_income NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_asset_performance_snapshot (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, property_id TEXT, code TEXT, reporting_period TEXT, occupancy_rate NUMERIC(12,2), delinquency_rate NUMERIC(12,2), status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_assistant_artifact (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, artifact_type TEXT, target_table TEXT, action TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_policy_rule (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, compiled_hash TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_runtime_parameter (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, value TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_schema_extension (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, target_table TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_control_assertion (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, assertion_type TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_governed_model (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, code TEXT, model_name TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_appgen_outbox_event (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, event_type TEXT, topic TEXT, idempotency_key TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_appgen_inbox_event (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, event_type TEXT, topic TEXT, idempotency_key TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
CREATE TABLE IF NOT EXISTS real_estate_property_management_appgen_dead_letter_event (id TEXT PRIMARY KEY, tenant TEXT NOT NULL, event_type TEXT, topic TEXT, idempotency_key TEXT, status TEXT, payload JSON, created_at TEXT, updated_at TEXT);
